-- Create "workflow_business_states" table
CREATE TABLE "workflow_business_states" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "source_type" character varying NOT NULL,
  "source_id" bigint NOT NULL,
  "source_no" character varying NULL,
  "order_id" bigint NULL,
  "batch_id" bigint NULL,
  "business_status_key" character varying NOT NULL,
  "owner_role_key" character varying NULL,
  "blocked_reason" character varying NULL,
  "status_changed_at" timestamptz NOT NULL,
  "payload" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "workflowbusinessstate_business_status_key" to table: "workflow_business_states"
CREATE INDEX "workflowbusinessstate_business_status_key" ON "workflow_business_states" ("business_status_key");
-- Create index "workflowbusinessstate_order_id_batch_id" to table: "workflow_business_states"
CREATE INDEX "workflowbusinessstate_order_id_batch_id" ON "workflow_business_states" ("order_id", "batch_id");
-- Create index "workflowbusinessstate_source_type_source_id" to table: "workflow_business_states"
CREATE UNIQUE INDEX "workflowbusinessstate_source_type_source_id" ON "workflow_business_states" ("source_type", "source_id");
-- Create "workflow_tasks" table
CREATE TABLE "workflow_tasks" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "task_code" character varying NOT NULL,
  "task_group" character varying NOT NULL,
  "task_name" character varying NOT NULL,
  "source_type" character varying NOT NULL,
  "source_id" bigint NOT NULL,
  "source_no" character varying NULL,
  "business_status_key" character varying NULL,
  "task_status_key" character varying NOT NULL,
  "owner_role_key" character varying NOT NULL,
  "assignee_id" bigint NULL,
  "priority" smallint NOT NULL DEFAULT 0,
  "blocked_reason" character varying NULL,
  "due_at" timestamptz NULL,
  "started_at" timestamptz NULL,
  "completed_at" timestamptz NULL,
  "closed_at" timestamptz NULL,
  "payload" jsonb NULL,
  "created_by" bigint NULL,
  "updated_by" bigint NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "workflowtask_due_at" to table: "workflow_tasks"
CREATE INDEX "workflowtask_due_at" ON "workflow_tasks" ("due_at");
-- Create index "workflowtask_owner_role_key_task_status_key" to table: "workflow_tasks"
CREATE INDEX "workflowtask_owner_role_key_task_status_key" ON "workflow_tasks" ("owner_role_key", "task_status_key");
-- Create index "workflowtask_source_type_source_id" to table: "workflow_tasks"
CREATE INDEX "workflowtask_source_type_source_id" ON "workflow_tasks" ("source_type", "source_id");
-- Create index "workflowtask_task_code" to table: "workflow_tasks"
CREATE UNIQUE INDEX "workflowtask_task_code" ON "workflow_tasks" ("task_code");
-- Create "workflow_task_events" table
CREATE TABLE "workflow_task_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "event_type" character varying NOT NULL,
  "from_status_key" character varying NULL,
  "to_status_key" character varying NULL,
  "actor_role_key" character varying NULL,
  "actor_id" bigint NULL,
  "reason" character varying NULL,
  "payload" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "task_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "workflow_task_events_workflow_tasks_events" FOREIGN KEY ("task_id") REFERENCES "workflow_tasks" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "workflowtaskevent_task_id_created_at" to table: "workflow_task_events"
CREATE INDEX "workflowtaskevent_task_id_created_at" ON "workflow_task_events" ("task_id", "created_at");
